return $input.all().map((item, index) => {
  const executionData = item.json.data.resultData.runData;
  const savedData = $('Get video list').all()[index];
  let output = {};

  output = {
    date: $('Edit Fields').first().json.date,
    epoch: parseInt(savedData.json.epoch, 10),
    start_time: savedData.json.start_time,
    end_time: savedData.json.end_time,
    file_name: savedData.json.mp4_path,
  };

  if ('Input Parameters' in executionData) {
    const input_parameter_node = executionData['Input Parameters'][0];

    if (input_parameter_node.executionStatus === "success") {
      const node_output = input_parameter_node.data.main[0][0];

      if (node_output && "json" in node_output) {
        const maxEpoch = node_output.json.maxEpoch;
        const jobPortalList = node_output.json.job_portal_list;
        const index = Math.floor(output['epoch'] / Math.floor(maxEpoch / jobPortalList.length));

        output = {
          ...output,
          job_portal: jobPortalList[index]
        }
      }
    }
  }

  if ('Job Scrapper' in executionData) {
    const job_scrapper = executionData['Job Scrapper'][0];

    if (job_scrapper.executionStatus === "success") {
      const node_output = job_scrapper.data.main[0][0];

      if (node_output && "json" in node_output) {
        output = {
          ...output,
          job_count: node_output.json.num_job_scrapped,
        }
      }
    }
  }

  if ('Upload a video' in executionData) {
    const video_upload = executionData['Upload a video'][0];

    if (video_upload.executionStatus === "success") {
      const node_output = video_upload.data.main[0][0];

      if (node_output && "json" in node_output) {
        output = {
          ...output,
          youtube_video_id: node_output.json.uploadId,
        }
      }
    }
  }

  return {
    json: {
      output: output
    }
  }
})

parameters.text:
=# N8N YouTube Video Report Email Prompt

Create an internal email to report that new video(s) have been created and uploaded to YouTube using the following n8n execution data.

## Input Data:
{{ (() => {
  return $json.output.map((item, index) => {
    const hasVideoId = item.youtube_video_id && item.youtube_video_id !== 'undefined';
    const hasFilename = item.file_name && item.file_name !== 'undefined';
    return `
Video ${index + 1}
- Date: ${item.date}
- Start Time: ${item.start_time}
- End Time: ${item.end_time}
- Filename: ${item.file_name}
- Job Portal: ${item.job_portal}
- Jobs Scrapped: ${item.job_count}
- Video Created: ${hasFilename ? 'YES' : 'NO'}
- YouTube Video ID: ${hasVideoId ? item.youtube_video_id : 'NOT UPLOADED'}
- YouTube Link: ${hasVideoId ? 'https://www.youtube.com/watch?v=' + item.youtube_video_id : 'N/A'}
- Thumbnail: ${hasVideoId ? 'https://img.youtube.com/vi/' + item.youtube_video_id + '/maxresdefault.jpg' : 'N/A'}
- YouTube Upload Status: ${hasVideoId ? 'UPLOADED' : 'PENDING'}
    `;
  }).join('\n---\n');
})() }}

## Email Requirements:
- This output will be processed by an HTML node, then sent via SMTP
- From: n8n Automation System
- Internal team notification only
- Tone: Clear, concise, and professional
- Format output as **structured JSON** for easy parsing in the HTML node

## Output Format:
Return a JSON object with the following structure:

```json
{
  "subject": "[Clear subject line summarizing the report for video created]",
  "videos": [
    {
      "index": 1,
      "date": "...",
      "start_time": "...",
      "end_time": "...",
      "filename": "...",
      "job_portal": "...",
      "job_count": "...",
      "youtube_video_id": "... or null",
      "youtube_link": "https://www.youtube.com/watch?v=... or null",
      "thumbnail_url": "https://img.youtube.com/vi/.../maxresdefault.jpg or null",
      "upload_status": "SUCCESS or FAILED"
    }
  ],
  "summary": "[Brief summary text about the automated upload]",
  "stats": {
    "total": 0,
    "successful": 0,
    "failed": 0
  }
}
```

## Instructions:
1. Generate a compelling subject line that includes the number of videos created
2. For each video, extract all relevant data fields
3. **Handle missing youtube_video_id**: If undefined/null, set upload_status to "FAILED" and set youtube_link and thumbnail_url to null
4. Generate YouTube links and thumbnail URLs only when video ID is present
5. Add a brief summary highlighting success/failure statistics
6. Calculate stats: total videos, successful uploads, failed uploads
7. Return everything as valid JSON for the next HTML node to consume

**Important:** 
- Check if youtube_video_id exists before generating links/thumbnails
- The JSON output will be used in an HTML template to create visually separated cards/sections
- Failed uploads should be clearly marked with appropriate messaging
- Include visual indicators (colors/icons) suggestion for failed vs successful uploads in the summary

parameters.inputSchema:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "N8N Video Creation Report Output Schema",
  "type": "object",
  "properties": {
    "subject": {
      "type": "string",
      "description": "Email subject line summarizing video creation",
      "minLength": 1,
      "maxLength": 200
    },
    "videos": {
      "type": "array",
      "description": "Array of successfully created video objects",
      "minItems": 1,
      "items": {
        "type": "object",
        "properties": {
          "index": {
            "type": "integer",
            "description": "Sequential video number",
            "minimum": 1
          },
          "date": {
            "type": "string",
            "description": "Video creation date"
          },
          "start_time": {
            "type": "string",
            "description": "Video start time"
          },
          "end_time": {
            "type": ["string", "null"],
            "description": "Video end time"
          },
          "filename": {
            "type": ["string", "null"],
            "description": "Original video filename"
          },
          "job_portal": {
            "type": "string",
            "description": "Source job portal name"
          },
          "job_count": {
            "type": ["string", "number"],
            "description": "Number of jobs scraped"
          },
          "youtube_video_id": {
            "type": ["string", "null"],
            "description": "YouTube video ID (null if YouTube upload pending)"
          },
          "youtube_link": {
            "type": ["string", "null"],
            "description": "Full YouTube video URL (null if YouTube upload pending)"
          },
          "thumbnail_url": {
            "type": ["string", "null"],
            "description": "YouTube thumbnail image URL (null if YouTube upload pending)"
          },
          "youtube_uploaded": {
            "type": "boolean",
            "description": "Whether video was successfully uploaded to YouTube"
          }
        },
        "required": [
          "index",
          "date",
          "start_time",
          "job_portal",
          "youtube_uploaded"
        ],
        "additionalProperties": false
      }
    },
    "summary": {
      "type": "string",
      "description": "Brief summary text about video creation and YouTube upload status",
      "minLength": 1,
      "maxLength": 500
    },
    "stats": {
      "type": "object",
      "description": "Summary statistics for the video batch",
      "properties": {
        "total_videos": {
          "type": "integer",
          "description": "Total number of videos created",
          "minimum": 0
        },
        "youtube_uploaded": {
          "type": "integer",
          "description": "Number of videos uploaded to YouTube",
          "minimum": 0
        },
        "youtube_pending": {
          "type": "integer",
          "description": "Number of videos pending YouTube upload",
          "minimum": 0
        }
      },
      "required": ["total_videos", "youtube_uploaded", "youtube_pending"],
      "additionalProperties": false
    }
  },
  "required": ["subject", "videos", "summary", "stats"],
  "additionalProperties": false
}
